var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"로터스 외곽은 위험한 지역이에요.","JPN":"ロータス外郭はとても危険なエリアです。","ENG":"The outskirts of Lotus are a dangerous place.","TWN":"洛德斯郊區很危險。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"모래폭풍이 주기적으로 불기도 하고, 용병들은 치안 유지라는 이유로 온갖 범죄를 일삼죠.","JPN":"砂嵐が定期的に発生し、傭兵たちは治安維持をいいことに、平気で犯罪を犯す場所です。","ENG":"Sandstorms occur on a regular basis, and mercenaries commit all kinds of crimes in the name of public order.","TWN":"不只定期會出現沙塵暴，還有一群傭兵以維護治安為名，實則專幹一些非法的事。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아무튼, 환청은 괜찮은 거예요?","JPN":"それより、幻聴はもう治まりましたか？","ENG":"Besides that, are you okay with having auditory hallucinations?","TWN":"倒是你的幻聽還好嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"보통 침식 증후군에 걸리면 자주 일어나는 증상인데…….","JPN":"侵食症候群になったときに発症する症状とよく似ているのですが……","ENG":"It's a common symptom of those who suffer from the Corruption Syndrome...","TWN":"通常幻聽是得到侵蝕症候群會出現的症狀……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 워치는 멀쩡하다. 덧붙여, 내 몸 상태도 환청을 제외하면 멀쩡해.","JPN":"私のウォッチは正常だ。身体の調子も幻聴以外は問題ない。","ENG":"My Watch is fine. Also, except for hearing things, my physical condition is superb.","TWN":"我的能量環還好好的，而且我的身體除幻聽外也沒什麼問題。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"추측이지만, 환청은…… 어쩌면 내가 기억을 잃은 것에 대한 반동일지도 몰라.","JPN":"おそらくだが……幻聴は記憶を失っていることによって、引き起こされているのかもしれない。","ENG":"It's just a guess, but hearing things... might be a reaction to the memories I've lost.","TWN":"這只是我的推測，或許……是因為我失去記憶才會產生幻聽。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇게 말씀하신다면 저야 믿는 수밖에 없죠.","JPN":"そうおっしゃるのなら、私は信じるしかないですけど。","ENG":"I can only trust your word on that.","TWN":"既然你這麼說，那我也只好姑且信你囉。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"뭐라도 떠오르시거나, 몸 상태가 이상하면 바로 말씀하셔야 해요?","JPN":"もし何か思い出したり、身体の調子がおかしかったら言ってくださいね？","ENG":"If you recall anything or if you feel strange, you must tell me right away, okay?","TWN":"如果你又想起什麼，或是身體有什麼狀況，一定要馬上跟我說喔？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"알겠다. 문제가 생기면 바로 보고하도록 하지.","JPN":"わかった。異変を感じたらすぐに言おう。","ENG":"Okay. I'll tell you immediately if something happens.","TWN":"好，有狀況我會立刻跟你報告。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우릴 버리지 마세요! 살려주세요! 아디트야!</color>","JPN":"<color=#ff3636>私たちを見捨てないで！　助けて！　アーディティヤ！</color>","ENG":"<color=#ff3636>Don't leave us! Save us! Aditya!</color>","TWN":"<color=#ff3636>不要扔下我們！救命！阿迪亞！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>아디트야. 이곳은 빛 한 점 들지 않아요. 너무 어두워요. 살려주세요.</color>","JPN":"<color=#ff3636>アーディティヤ。ここには光も届かない。真っ暗です。助けてください。</color>","ENG":"<color=#ff3636>Aditya. There is not a single ray of light here. It's so dark. Please come save us.</color>","TWN":"<color=#ff3636>阿迪亞，這裡是黑暗之地，一點光都沒有，快救救我們。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어혼자는싫어</color>","JPN":"<color=#ff3636>一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌一人は嫌</color>","ENG":"<color=#ff3636>Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.Idon'twanttobealone.</color>","TWN":"<color=#ff3636>我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人我不想自己一個人</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님! 괜찮으세요?!","JPN":"アーディティヤ様！　大丈夫ですか！？","ENG":"Miss Aditya! Are you okay?!","TWN":"阿迪亞！你沒事吧？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"환청이…… 심해지고 있어……!","JPN":"幻聴が……激しくなった……！","ENG":"The auditory hallucinations... They are getting worse...!","TWN":"幻聽……變嚴重了……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아, 아디트야 님! 침식체들이 나타났어요!","JPN":"あっ、アーディティヤ様！　侵食体の群れです！","ENG":"M-Miss Aditya! C.O.s have appeared!","TWN":"阿，阿迪亞！有侵蝕體！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"분명 이 근처는 침식 재난이 발생하지 않은 구역이에요. 어째서 이런 일이……?","JPN":"ここ一帯は侵食災害の被害区域ではないのに、どうして……？","ENG":"How can this happen...? A Corruption Disaster doesn't occur around here.","TWN":"這附近明明是不會發生侵蝕災難的區域，怎麼會……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"당장 관리국에 지원을 요청해야 해요!","JPN":"と、とにかく！　今すぐ管理局に支援要請を出さないと！","ENG":"We need to request help from the Administration right now!","TWN":"必須立刻向管理局請求支援！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……내 뒤로 물러서라. 아샤.","JPN":"……私の後ろに隠れろ、アーシャ。","ENG":"...Get behind me, Asha.","TWN":"……到我後面，阿莎。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아까보다 상태가 더 안 좋아지신 것 같아요. 너무 위험하다고요.","JPN":"さっきより体調が悪くなっているんじゃないですか？　危険すぎますよ！","ENG":"You look worse than just before. This is too dangerous.","TWN":"你現在的狀態比剛才還要差，這樣太危險了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아무리 상태가 안 좋아도, 잔챙이들 정도는 상대할 수 있다.","JPN":"いくら体調が悪くなろうが、雑魚ぐらいは対処できる。","ENG":"No matter how bad my condition is, I can deal with those grunts without a problem.","TWN":"就算我狀態不好，對付幾隻小嘍囉還是可以的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"지원을 기다리기엔 상황이 너무 촉박해.","JPN":"支援が来るまで待てる状況ではない。","ENG":"The situation is too urgent to wait for help to arrive.","TWN":"現在沒時間等候支援了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"놈들을…… 정화하겠다.\xA0","JPN":"奴らを……浄化する。\xA0","ENG":"I will purify... them.\xA0","TWN":"我要……淨化它們。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};